sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    var ga = new GlideAjax('CandidateDetails');

    ga.addParam(
        'sysparm_name',
        'getCandidateData'
    );

    ga.addParam(
        'sysparm_candidate',
        newValue
    );

    ga.getXMLAnswer(function(answer) {

        var data =
            JSON.parse(answer);

        g_form.setValue(
            'name',
            data.name
        );

        g_form.setValue(
            'job_title',
            data.job_title
        );

        g_form.setValue(
            'resume_score',
            data.resume_score
        );

        g_form.setValue(
            'skill_match',
            data.skill_match
        );

        g_form.setValue(
            'status',
            data.status
        );

        g_form.setValue(
            'ai_recommendation',
            data.ai_recommendation
        );

        g_form.setValue(
            'interview_date',
            data.interview_date
        );

        g_form.setValue(
            'ai_feedback',
            data.ai_feedback
        );

    });

}
